var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"작전 종료. 집으로 돌아갈 시간이야.","JPN":"作戦終了。家に帰る時間だよ。","ENG":"Mission complete. It's time to go home.","TWN":"作戰結束。是時候回家了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"참, 말했던 비품은 챙겼어?","JPN":"そういえば、備品は持ってきた？","ENG":"By the way, did you grab the supplies I mentioned?","TWN":"對了，你說的東西帶了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"비품?","JPN":"備品？","ENG":"Supplies?","TWN":"東西？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"또 까먹은 거야? 이번 경연 출품에 꼭 필요한 비품이 있다고 했잖아.","JPN":"また忘れたの？　今回のコンテスト出品に欠かせない備品があるって言ったじゃん。","ENG":"You forgot again? I told you we needed those for the competition entry.","TWN":"你又忘了嗎？我說過這次比賽展出，必須要有那個東西。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"정말-","JPN":"もう～","ENG":"Ugh…","TWN":"真是的—"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"내가 왜 어제 말한 것도 까먹고 기계도 만질 줄 모르는 사람이랑 일하게 된 건지 모르겠다니까.","JPN":"なんで昨日言ったことも1日で忘れる機械音痴と一緒に働くことになったのやら。","ENG":"I still don't get why I ended up working with someone who forgets everything I said just the day before and can't even handle machines.","TWN":"我真不明白，為什麼我會和一個連昨天說過的話都會忘記，也不會操作機器的人一起工作。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내가 너보다 강하기 때문이다.","JPN":"私がお前より強いからだ。","ENG":"Because I'm stronger than you.","TWN":"因為她比你更強。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"네 네- 내일 채굴 호위도 잘 부탁드립니다, 파트너 어르신-","JPN":"はい、はい～明日の採掘の護衛もどうぞよろしくお願いしますよ。パートナーのおばあさん～","ENG":"Yeah, yeah. Thanks in advance for guarding the mining site tomorrow, granny.","TWN":"是是—明天的採礦護衛也拜託你了，夥伴阿姨—"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"용병 일이 돈이 된다는 건 인정하지만, 왜 그렇게 채굴 의뢰에 집착하지?","JPN":"傭兵の仕事が儲かることは分かるが、なぜそこまで採掘の依頼にこだわる？","ENG":"I'll admit mercenary work pays well, but why are you so obsessed with mining jobs?","TWN":"傭兵的工作賺錢是沒錯，但你為什麼這麼執著於採礦委託？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그야 내 능력이 막힌 길을 뚫는데 유용하니까.","JPN":"そりゃもちろん、私の能力は塞がった道を開けるのに有用だから。","ENG":"Because my abilities are perfect for clearing blocked paths.","TWN":"因為我的能力很適合開闢堵塞的道路啊。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"업계에서도 이제 제법 유명해. 길 잘 뚫는 여자로.","JPN":"業界でも結構有名なんだよ。道開けが上手い女だって。","ENG":"I'm kind of famous for that now. You know, as the girl who opens the way.","TWN":"在業界已經小有名氣了。是個很會開路的女人。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"공고에는 뭐든 잘 녹이는 여자라고 되어있던데.","JPN":"募集には、何でも溶かす女だと書いてあったが。","ENG":"I saw a listing that called you the girl who melts anything.","TWN":"但公告上寫著是個很會溶解東西的女人。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"별명은 많은 편이 유명세를 타기 쉽거든.","JPN":"二つ名は多いほど有名になりやすいんだ。","ENG":"Catchy names make for better marketing.","TWN":"外號多一點比較容易出名嘛。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그렇게 내가 계속 의뢰를 받아야 어르신을 계속 부려 먹지. 우리 순진한 어르신을 냉혹한 사기꾼들이 넘치는 사회로 내보낼 순 없잖아.","JPN":"そうやって私がどんどん依頼を受けないと、おばあさんを雇えないでしょう。ピュアなおばあさんを冷酷な詐欺師が蔓延る社会へ送り出すわけにはいかないじゃん。","ENG":"Besides, I need steady gigs if I'm gonna keep bossing you around. No way I'm letting sweet ol' granny loose in a world full of scammers.","TWN":"只有我繼續接委託，才能繼續操縱你。不能把我們單純的阿姨丟到充斥冷酷騙子的社會裡去吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"혹시 채광 의뢰에 집착하는 이유가…","JPN":"もしかして採掘の依頼に執着するのは……","ENG":"Wait, are you taking mining jobs because…","TWN":"你這麼執著於採礦委託…"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아직도 <color=#ffd34c>검은 이터니움</color>을 찾고 있기 때문인가?","JPN":"まだ<color=#ffd34c>黒いエタニウム</color>を探しているからなのか？","ENG":"You're still looking for the <color=#ffd34c>Dark Eternium</color>?","TWN":"是不是還在找<color=#ffd34c>黑色永恆之金</color>？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"술김에 얘기했던 건데, 그건 잘도 기억하네.","JPN":"酔っぱらってポロっと話しただけなのに、よく覚えてるんだね。","ENG":"Wow, you actually remembered that? I only said it while tipsy.","TWN":"那是酒後說的，你倒是記得很清楚。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 얘길 할 때까지만 해도 난 네가 애정결핍에 시달리는 환자라고 생각했다.","JPN":"あの話を聞くまで、私はお前のことを愛情の欠如に悩む患者だと思っていた。","ENG":"Back then, I thought you were just some lonely nutcase.","TWN":"說那話的時候，我還以為你是個患有情感缺失症的患者。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"갑자기 아무 이유없이 허전함을 느낀 적 없냐느니, 검은 이터니움에 비친 어떤 남자를 봤다느니 같은 헛소리를 지껄여서 말이지.","JPN":"突然わけもなく虚しさを感じることはないかとか、黒いエタニウムの中にある男を見たとかいう戯言を言うものだから。","ENG":"Randomly asking if I felt empty, and spouting nonsense about seeing some guy in the Dark Eternium.","TWN":"你說什麼毫無理由感到空虛，又說在黑色永恆之金裡看到了某個男人，說些瘋言瘋語。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 말처럼…","JPN":"確かに……","ENG":"Like you said…","TWN":"也許就像你說的…"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"내가 이상한 걸지도 모르겠네.","JPN":"私、おかしいのかもしれないね。","ENG":"Maybe I am crazy.","TWN":"是我不正常吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"침식지대를 자주 들락거리는 사람이 착란증세를 겪는 건, 제법 흔한 일이니까.","JPN":"侵食地帯に頻繁に出入りする人間が錯乱状態に陥るのはよくあることだし。","ENG":"It's not unusual. People who visit Corrupted Areas often enough tend to lose their grip.","TWN":"經常出入侵蝕區的人，產生幻覺是很常見的事。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"채광 의뢰가 부담되면 관둬도 돼. 어르신을 억지로 붙잡진 않을게.","JPN":"採掘依頼につき合うのが負担になるなら、やめていいんだよ。おばあさんに無理強いはしない。","ENG":"If the mining jobs are too much, you can drop out. I won't stop you.","TWN":"如果採礦委託讓你覺得有壓力，放棄也沒關係。我不會強留你。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"관두겠다는 말은 한 적 없어.","JPN":"……やめるとは言っていない。","ENG":"I never said I was quitting.","TWN":"我沒說要放棄。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"나야 네 회사에서 월급만 받으면 그만이니까.","JPN":"私はお前の会社から給料がもらえばそれでいい。","ENG":"I just want my paycheck.","TWN":"我只要能從你公司領薪水就行。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"또 술집에서 번 돈 탕진하러 가는 거야?","JPN":"また給料使い果たしに酒場に行くの？","ENG":"Heading off to blow your salary at another bar again?","TWN":"你又要去把在酒館賺的錢花光嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"신경 끄고 잠이나 자라. 꼬맹이.","JPN":"余計なお世話だ。寝ろ、ガキ。","ENG":"Mind your business and get some sleep, kid.","TWN":"別管我，睡你的覺吧，小鬼。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"키 안 크니까.","JPN":"そんなんじゃ背伸びないぞ。","ENG":"You're not gonna grow any taller otherwise.","TWN":"會長不高的。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…흥.","JPN":"……ふん。","ENG":"…Hmph.","TWN":"…哼。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"나랑 키 차이도 별로 안 나면서 무슨.","JPN":"なによ、私とあんま変わんないくせに。","ENG":"Says the one barely taller than me.","TWN":"明明和我身高差不了多少，還說什麼。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"이번엔 먼저 와있었군요.","JPN":"今日は先に来てたんですね。","ENG":"You're early this time.","TWN":"這次你先到了啊。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BELL"},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"드디어 같이 일해볼 마음이 든 건가요?","JPN":"やっと一緒に働く気になってくれたんですか？","ENG":"Ready to finally work together?","TWN":"終於有心和我一起工作了嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그 얘기보다 먼저 약속한 게 있을 텐데?","JPN":"その話をする前に、約束したものがあるはずだが。","ENG":"Weren't we supposed to talk about something else first?","TWN":"在這之前，是不是還有個約定好的事情？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 성급하시네요.","JPN":"はは、気が早いですね。","ENG":"Haha, no patience as always.","TWN":"哈哈，你真是心急。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이번 정보는 특별히 서면으로 준비했습니다. 데이터 메모리로 전해드렸다간 또 확인도 전에 망가질 것 같아서요.","JPN":"今回の情報は特別に書類で用意しました。データーメモリーだと、また閲覧前に壊れそうですからね。","ENG":"I brought a hard copy of the info. I figured if I gave you a data memory, it'd be fried before you even opened it.","TWN":"這次的情報我特別準備了書面資料。怕傳送給你資料記憶體，又會在你確認之前就壞掉。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L47_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…인자 복제 실험?","JPN":"……ファクター複製実験？","ENG":"…Factor cloning experiments?","TWN":"…因子複製實驗？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 비밀이 많다는 관리국조차 모르게 진행됐던 연구에요.","JPN":"あの管理局にすら秘密で行われた研究です。","ENG":"Research even the secretive Administration didn't know about.","TWN":"這是在秘密最多的管理局裡，甚至連他們自己都不知道的實驗。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이지수 씨가 검은 이터니움을 통해 봤다던 관리국의 연구소는 실존하더군요.","JPN":"ムラサメさんが黒いエタニウムを通して見たという管理局の研究所は実在していました。","ENG":"The Administration's lab you said you saw through the Dark Eternium is real.","TWN":"李智秀透過黑色永恆之金看到的管理局研究室，確實存在。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 실험을 계획하고 실행에 옮긴 사람이 누군지도 알아내긴 했지만… 지금 그건 당신에게 별로 중요한 얘기가 아닐 테니 넘어가죠.","JPN":"その実験を計画し、実行した人間が誰かについても突き止めましたが……今のあなたにはさほど重要な話ではありませんから、置いておきましょう。","ENG":"I also found out who planned and ran the whole thing… but I doubt that's what matters to you right now. So let's move on.","TWN":"我也查出是誰計畫並執行了這個實驗…但現在這對你來說並不重要，就跳過吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신이 알고 싶어했던 건, 당신의 과거일 테니까.","JPN":"あなたが知りたいのは、あなたの過去でしょうから。","ENG":"What you really want to know is the truth about your past.","TWN":"因為你想知道的，是你的過去。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"엄청 쏟아지네.","JPN":"降ってるなあ～","ENG":"Wow, it's really pouring.","TWN":"雨下得真大。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"비가 이렇게 오는데 언제 돌아오는 거야? 자기 빨래도 내가 다 걷어줬구만.","JPN":"雨がこんなに降ってるのにいつ帰ってくるんだろ？　おばあさんの分の洗濯物も全部取り込んであげたってのに。","ENG":"It's raining cats and dogs, so when is she coming back? I even brought in her laundry.","TWN":"雨下這麼大，你什麼時候回來啊？你的衣服我都幫你收好了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"잠깐, 요즘 늦게까지 도시에 나다니면서 술냄새도 나는 게 혹시…","JPN":"まてよ、最近遅くまで都市に出かけて、酒臭くなって帰ってくるのってまさか……","ENG":"Wait, she's been staying out late in the city smelling like booze lately…","TWN":"等等，最近你是不是經常晚上待在市區，身上又有酒味，難道是…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"만나는 남자라도 생긴 건…?","JPN":"男ができた……？","ENG":"Does she have a new boyfriend or something…?","TWN":"交男朋友了…？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그런 남모를 취미가 있는 줄 몰랐군.","JPN":"そんな隠れた趣味があったとは知らなかったな。","ENG":"I didn't know you had such a hobby.","TWN":"沒想到你有這種不為人知的嗜好。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"혼잣말로 내 흉을 보고 있다니 말야.","JPN":"独り言で私の陰口を叩く趣味が。","ENG":"Muttering complaints about me to yourself.","TWN":"居然在自言自語地說我壞話。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"흉이라뇨- 좋은 인연을 만나는 게 얼마나 축복인데.","JPN":"陰口だなんて！　いい人に出会うのはめでたいことでしょ。","ENG":"Complaints? Please. Meeting someone special is a blessing, you know.","TWN":"說什麼壞話—遇到好的緣分是多大的福氣啊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐, 어르신이랑 전화 대신 편지로 연락해야 할 남자 분은 쬐끔 불쌍하겠지만?","JPN":"まあ、おばあさんとやり取りする時に電話の代わりに手紙を出す羽目になる男性側がちょっと可哀想ではあるけど。","ENG":"Though I do feel a bit sorry for the guy. He'll probably have to write you letters instead of calling.","TWN":"不過，那位得用信而不是電話和你聯絡的男朋友，可能就有點可憐了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…준비해. 내일 아침에 바로 출발한다.","JPN":"……準備しろ。明日の朝出発する。","ENG":"…Get ready. We leave first thing in the morning.","TWN":"…準備好。明天一早立刻出發。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"준비? 어디 가려고?","JPN":"準備？　どこに行くの？","ENG":"Get ready? For what?","TWN":"準備？要去哪？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"으, 싸늘해. 심장에 에어컨을 쐬는 것 같아.","JPN":"うう、寒い。心臓にエアコンつけてるみたい。","ENG":"Brr, so cold. Feels like an AC blast straight to the heart.","TWN":"嗚，好冷。感覺心臟被吹冷氣一樣。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"침식지대는 많이 가봤지만… 이면세계는 처음이네.","JPN":"侵食地帯はたくさん行ったけど……裏世界は初めてだよ。","ENG":"I've been to a lot of Corrupted Areas, but this is my first time in the Counterside.","TWN":"雖然去過很多侵蝕區…但異界還是第一次。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"차원함선은 어떻게 빌렸어?","JPN":"次元艦船なんてどこで借りたの？","ENG":"How'd you even get your hands on a dimensional ship?","TWN":"你怎麼借到次元艦船的？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"술집에서 만난 사람에게 의뢰를 받았다. 그랬더니 빌려주더군.","JPN":"酒場で会った人から依頼を受けた。そうしたら貸してくれてな。","ENG":"Someone at a bar offered a job. Said I could borrow it.","TWN":"在酒館裡接到一個人的委託。然後他就借我了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"되게… 간단하구나.","JPN":"なんか……簡単だなあ。","ENG":"That's… awfully convenient.","TWN":"這麼…簡單嗎。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"관리국 공식 의뢰도 아닌데, 신용 해도 되는 거 맞아?","JPN":"管理局公認の依頼でもないのに、その人信用していいの？","ENG":"And you trust this person? This isn't even an official Administration job.","TWN":"這又不是管理局的正式委託，可以相信他嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"의뢰인도 관리국 출신이다. 지금 우리가 타고 온 것만 봐도 그게 거짓말이 아니란 건 알 수 있지.","JPN":"依頼人も管理局出身だ。私たちが艦船に乗って無事来れたことを見ても、嘘じゃないことがわかる。","ENG":"The client's ex-Administration. Just seeing the ship should tell you they're legit.","TWN":"委託人也是管理局出身。光是我們現在搭的這艘船，你就知道他說的不是謊話。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"하긴, 관리국에서 저런 함선을 훔친 거라면 진작 온 세상에 수배령이 떨어졌을 테니까.","JPN":"確かに管理局からあんな艦船盗んだら、世界的に指名手配されちゃうもんね。","ENG":"Fair point. If they stole that from the Administration, the whole world would be on alert by now.","TWN":"也是，如果管理局的艦船被偷，早就向全世界發布通緝令了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그래서 우리가 해야 할 일은- 이 어딘가에 꽂힌 관측도구를 찾아서 데이터만 회수하면 된다는 거지?","JPN":"それで、私たちは……この辺のどこかに刺さってる観測道具を探し出して、データだけ回収すればいいんだよね？","ENG":"So all we have to do is find the observation device somewhere in here and retrieve the data, right?","TWN":"所以我們要做的—就是在這某處找到觀測工具，回收資料就行了？"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래. 위험 수준만 따지면 나 혼자로 충분하지만, 관건은 데이터를 가지고 돌아가는 거니까.","JPN":"ああ。危険度だけ見れば私一人でも十分なんだが、肝心なのはデータ回収のほうだからな。","ENG":"Yeah. It's dangerous, but if it were just that, I could've handled it alone. What matters is retrieving the data.","TWN":"對。如果只論危險程度，我一個人就夠了，但關鍵是把資料帶回去。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"여기서 필요한 데이터 외에 뭔가 값져 보이는 걸 우연히 찾게 되면 어떡해-?","JPN":"ここで必要なデータの他に何か金目のものを偶然見つけたらどうすればいい？","ENG":"What if, by chance, we also happen to find something valuable?","TWN":"如果我們在這裡，偶然發現了除了必要資料之外，還有看起來很值錢的東西怎麼辦—？"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…반환 절차 없이 우리가 갖는다. 공식 의뢰가 아니니까.","JPN":"……返還手続きなしで私たちが取得する。公式依頼じゃないからな。","ENG":"…Then we keep it. It's not an official job, remember?","TWN":"…不用經過返還程序，我們自己拿走。反正這又不是正式委託。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"앗싸! 열심히 찾아야지!","JPN":"やった！　頑張って探すぞ！","ENG":"Heck yeah! Time to start treasure hunting!","TWN":"太棒了！我要努力找！"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"귀한 아티팩트는 저런 동굴 안에 숨어있으려나?","JPN":"ああいう洞窟の中なら貴重なアーティファクトがあるかな？","ENG":"Maybe some special Artifact is hidden deep in a cave like that?","TWN":"珍貴的古文物會藏在這種洞穴裡嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"꺄아! 침식체다! 도와줘!","JPN":"きゃあ！　侵食体だ！　助けて！","ENG":"Kyaah! C.O.s! Help me!","TWN":"呀啊！是侵蝕體！救命！"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…뒤쪽에서도 오고 있으니, 거긴 네가 맡아.","JPN":"……後方からも来ている。そこはお前がやれ。","ENG":"…They're coming from behind, too. You handle that side.","TWN":"…後面也有，那裡交給你了。"},"stage":{"bg":"COUNTERSIDE_AURORA_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};